"""
托勒密《百論》（Centiloquy / 百則箴言）完整現代中文版
資料來源：Ashmand 1822 年英譯本（你提供的掃描檔案附錄）
"""

import random
from typing import List, Dict, Optional

# ==================== 托勒密《百論》100 條完整現代中文翻譯 ====================
CENTILOQUY: List[Dict] = [
    {"id": 1, "text": "判斷必須由自身經驗與學問共同調節；因為任何個人，無論多麼博學，都不可能預先宣告特定事件的具體形態。唯有受神靈啟發之人，方能預測具體細節。"},
    {"id": 2, "text": "當探究者對預期事件進行深思熟慮的考察時，將發現事件本身與其心中所構想者，並無實質差異。"},
    {"id": 3, "text": "凡能適應任何特定事件或追求者，其天性中必有相應之星象作為強烈指示。"},
    {"id": 4, "text": "善於知識的心智，比專精最高層次科學者更能迅速發現真理。"},
    {"id": 5, "text": "熟悉星象本質的能手，能預先避免許多星象效應，並在效應降臨前做好準備。"},
    {"id": 6, "text": "選擇合宜的日期與時辰甚為有利，前提是此人天性已臻完善。若天性不利，則無論事態看似多麼順利，選擇亦將徒然無效。"},
    {"id": 7, "text": "未事先掌握自然界中各種組合與變化的知識者，無法理解星辰交織影響之奧義。"},
    {"id": 8, "text": "睿智之心能提升天體運行之效能，正如巧農透過耕耘改善自然。"},
    {"id": 9, "text": "在命盤生成與腐化之形態中，受天體形態影響；故製造護身符者，常依星辰運行之時機而行事。"},
    {"id": 10, "text": "選擇吉日良辰時，應適度運用凶星，如同高明的醫生使用毒藥以達治療之效。"},
    {"id": 11, "text": "未明確所求之事質性之前，切勿輕率選定日期與時辰。"},
    {"id": 12, "text": "愛與恨皆妨礙正確判斷；因二者既可淡化至關重要之事，亦能放大瑣碎細節。"},
    {"id": 13, "text": "凡由天體構成所顯示之徵兆，無論輔助或有害之星，皆應納入考量。"},
    {"id": 14, "text": "當第七宮及其主宰星受損時，占星師將陷入錯誤的迷宮之中。"},
    {"id": 15, "text": "任何王國上升點所落之星座，其後繼星座即為該王國之敵人；但角度宮位與後續宮位則為其友人。此原則適用於所有學說與制度。"},
    {"id": 16, "text": "若第八宮可控制吉星之力，則會藉由善人之手帶來災禍；反之，若其狀態良好，則能防止災禍發生。"},
    {"id": 17, "text": "對年邁者未來壽命之預測，須待其尚餘歲數推算完畢後方可下判斷。"},
    {"id": 18, "text": "若一吉星雖升，但兩顆光體同處一度，則命主在一切事務上皆將同等且極為順遂。反之，若兩光體東西相對，則效果相反；倘若凶星位於上升點，更將產生反效果。"},
    {"id": 19, "text": "月球與木星相合時，將阻礙淨化療法之效力。"},
    {"id": 20, "text": "切勿以鐵器刺穿月球所主宰之身體部位。"},
    {"id": 21, "text": "當月球位於天蠍座或雙魚座時，淨化療法可有效運用，前提是上升點之主宰星需與地平線以下之星相合；若與地平線以上之星相合，則服下之藥物將被嘔吐而出。"},
    {"id": 22, "text": "月球位於獅子座時，切勿首次穿戴或收納任何衣物；若月球同時受凶相影響，情況將更為惡劣。"},
    {"id": 23, "text": "月球與星辰之間的相位，會賦予命主極大的行動力；若星辰力量強盛，則預示有效的行動；若星辰衰弱，則僅能激起無效的衝動。"},
    {"id": 24, "text": "若日月蝕發生於本命盤或年運盤的角度位置，則為不祥之兆；其影響程度取決於上升點與蝕點之間的距離。正如日蝕時，一年被視為一小時；同理，月蝕時，一個月亦被視為一小時。"},
    {"id": 25, "text": "若命主的象徵星位於天頂，應以正升度推算其運勢；若位於上升點，則需以該緯度的斜升度推算。"},
    {"id": 26, "text": "若某事的象徵星與太陽合相，且處於地平線下或非其本性所屬之宮位，則此事必遭隱蔽；反之，若該星從低落狀態提升至高處，並回歸其本位，則事態將顯現明朗。"},
    {"id": 27, "text": "金星能為命主帶來愉悅感，尤其當其所在星座主宰身體的某一部位時；其他行星亦同此理。"},
    {"id": 28, "text": "當月球無法與兩顆行星建立良好關係時，應設法讓月球與某顆恆星結合，藉由該恆星的特質來彌補不足。"},
    {"id": 29, "text": "恆星能賜予極佳的命運，但通常與理性無關；除非行星同時也支持此吉兆，否則恆星更常預示災難。"},
    {"id": 30, "text": "觀察任何王朝首位君王的誕生時刻；若其上升點與其子嗣的本命上升點相符，則其子必能繼承王位。"},
    {"id": 31, "text": "當統治某國之星進入氣候轉變之宮位時，國王或其重臣之一將死亡。"},
    {"id": 32, "text": "兩人之間的和諧關係，源於彼此星盤中星辰配置的協調性，此配置顯示雙方各自命盤中皆蘊含善意。"},
    {"id": 33, "text": "愛與恨可從日月的和諧與衝突，以及雙方本命上升點的互動中辨別；然而，遵循吉祥星象者，更能增進善意。"},
    {"id": 34, "text": "若新月所在宮位的主宰星位於角度，則預示該月內將發生重要事件。"},
    {"id": 35, "text": "當太陽行經任一星辰所在位置時，會激發該星辰在大氣中的影響力。"},
    {"id": 36, "text": "建城時，應考慮可能對城市有所助益的恆星；而建屋時，則須觀察行星。凡火星位於頂點的城市之君王，最常死於刀劍之下。"},
    {"id": 37, "text": "若處女座或雙魚座位於上升點，命主將自創尊榮；但若白羊座或天秤座位於上升點，則將自招死亡。其餘星座亦可依此類推。"},
    {"id": 38, "text": "水星若落於土星的任一宮位且得勢，將賦予命主思辨與探究的才智；若落於火星宮位，尤其在白羊座時，則賦予雄辯之才。"},
    {"id": 39, "text": "第十一宮受剋，預示國王之家宅與財庫將受損；第二宮受剋，則代表臣民財富蒙受損失。"},
    {"id": 40, "text": "當上升點受凶星壓制時，命主將沉溺於污穢之事，並喜愛惡臭之物。"},
    {"id": 41, "text": "離別之際，須警惕第八宮及其主宰星受剋；返程之時，則須留意第二宮及其主宰星受剋。"},
    {"id": 42, "text": "若疾病發作時，月亮正處於出生時被某凶星佔據之星座，或與該星座成四分相或對沖相，則病情將極為嚴重；若凶星同時也觀照該星座，則更為危險。反之，若月亮位於出生時由吉星所守護之位置，則無危險。"},
    {"id": 43, "text": "一國之凶星格局，會因現世不利星象而加強。"},
    {"id": 44, "text": "若病患之上升點抵抗自身本命盤之格局，且時運亦未帶來任何益處，乃不祥之兆。"},
    {"id": 45, "text": "若上升點或主要徵象星不在人道星座中，命主自身亦將背離人性常理。"},
    {"id": 46, "text": "若上升點落於固定星、新月角度，或王國命運點所在之宮位，則本命盤中將賦予大量幸福。"},
    {"id": 47, "text": "若某一命盤中的凶星落入另一命盤中吉星之位置，則擁有吉星者將遭受擁有凶星者之損害。"},
    {"id": 48, "text": "若王子之中天為其臣民之上升點，或雙方之主要徵象星呈吉祥相位，則二者將長期緊密相連。同理，若臣民或僕從之第六宮為其君主或主人之上升點，情況亦然。"},
    {"id": 49, "text": "若僕人的上升點位於主人命盤的中天，主人將對該僕人極度信任，甚至受其支配。"},
    {"id": 50, "text": "切勿忽視一百一十九種相位；因世間運作之知識——無論是生成或腐敗——皆依賴於此。"},
    {"id": 51, "text": "應以出生時月亮所佔星座，對照受孕時上升點所在星座；並考慮月亮在受孕時可能位於該星座，或其對宮星座，即為出生時的上升星座。"},
    {"id": 52, "text": "身材高大者，其命主星位於高升位置，上升點則位於星座起始處；而身材矮小者，其命主星則位於下降位置。同時亦須觀察星座是否正位或傾斜。"},
    {"id": 53, "text": "體型瘦弱或纖細者，其命主星無緯度；但體格魁梧或肥胖者則有緯度。若緯度偏南，命主性格活躍；若偏北，則性格消極。"},
    {"id": 54, "text": "建造房屋時，若主要主宰星與地平線以下之星同宮，將阻礙工程進展。"},
    {"id": 55, "text": "火星對船隻的惡性影響，若其既不在中天亦不在第十一宮，則會減弱；但若位於其中任一宮位，則易使船隻遭海盜劫掠。若上升點受火星本質的固定星影響，船隻將被焚毀。"},
    {"id": 56, "text": "當月亮處於第一象限，逐漸遠離與太陽的合相時，身體內的體液會擴張，直至第二象限；在其他象限則逐漸減少。"},
    {"id": 57, "text": "若病患期間第七宮及其宮主星受剋，應更換醫師。"},
    {"id": 58, "text": "觀察某相位的位置及其與年度上升點的距離；因事件將在預測時間到達該位置時發生。"},
    {"id": 59, "text": "在斷言某缺席者將死亡前，應先觀察他是否可能醉酒；在宣稱他將受傷前，應查看他是否可能放血；在說他將找到財寶前，應檢驗他是否可能取回自己的存款；因這些事象的星盤圖形可能相似。"},
    {"id": 60, "text": "病患情況下，應觀察關鍵日期，以及月亮在十六邊形圖形各角的行進狀況。若這些角度未受衝擊，對病患有利；若受衝擊，則屬不利。"},
    {"id": 61, "text": "月亮象徵身體事務，其運行方式與之相似。"},
    {"id": 62, "text": "若能精確標示合相的起始點，即可推斷接下來一個月的天氣變化。此判斷取決於各星體角度的主宰者，因他掌控大氣性質；同時亦須考慮當時現有天氣的品質。"},
    {"id": 63, "text": "在土星與木星合相時，應根據二者中位置較高者之本質來下結論。其他星體亦依此規則處理。"},
    {"id": 64, "text": "確定命主後，需檢視其在年度運轉或新月上升時所具影響力，並據此作出預言。"},
    {"id": 65, "text": "在最小合相中，觀察平均合相的差異；在平均合相中，則觀察最大合相的差異。"},
    {"id": 66, "text": "不可單憑保護星本身作判斷，亦須參考諸星的資格與阻礙狀況。"},
    {"id": 67, "text": "年份之吉凶受接收星體的無能所削弱。"},
    {"id": 68, "text": "兇星若為晨星，代表意外事故；若為昏星，則代表疾病。"},
    {"id": 69, "text": "若月亮與太陽對衝，且與霧狀星體相合，命主視力將受損；若月亮位於西側角度，而兩顆兇星位於東側角度，且太陽亦處於某角度時，命主將失明。"},
    {"id": 70, "text": "若月亮與水星毫無關聯，將導致瘋狂；若二者皆未與上升點連結，且土星夜間佔據角度、火星日間佔據角度（特別是在巨蟹座、處女座或雙魚座），則會引發邪靈侵擾。"},
    {"id": 71, "text": "若兩顆光體皆位於陽性星座，在男性命盤中，其作用符合自然法則；但若置於女性命盤中，則會增強其作用。火星與金星若為晨星，傾向男性特質；若為昏星，則傾向女性特質。"},
    {"id": 72, "text": "教育事務應由三重性上升主宰者評斷；生命事務則由條件性光體三重性主宰者評斷。"},
    {"id": 73, "text": "若太陽與蛇髮女妖之首同度，且無任何吉星照耀，第八宮亦無吉星，而命主的條件之星又與火星相衝或成四分相，則此人將遭斬首。若此條件之星達至頂點，其身體將受重創或毀損；若該四分相來自雙子座或雙魚座，則其手足將被截斷。"},
    {"id": 74, "text": "火星若為上升星，通常會在臉上留下疤痕。"},
    {"id": 75, "text": "若太陽與上升宮主星在獅子座合相，且火星在上升宮無主宰權力，第八宮亦無吉星，則此人將被火焚。"},
    {"id": 76, "text": "若土星居中天，且條件之星與其相衝，則此人將死於建築廢墟之中——前提是地平線以下星座為土象星座；若為水象星座，則將溺斃或窒息於水中；若為人象星座，則將遭人絞殺，或死於刑具或災禍。然而，若第八宮有吉星，雖不致死亡，但仍將瀕臨險境。"},
    {"id": 77, "text": "上升宮之保護用於影響身體之事；命運之點用於外在環境；月亮用於身體與靈魂之聯繫；中天則用於職業或事業。"},
    {"id": 78, "text": "一顆星常能對其無主宰權之地發揮影響，從而為命主帶來意料之外的好處。"},
    {"id": 79, "text": "凡火星位於第十一宮者，無法掌控其主人。"},
    {"id": 80, "text": "若金星與土星合相，且第七宮內有任何宮主星，則此人出身虛偽。"},
    {"id": 81, "text": "時間可依七種方式推算：即兩徵象星之間的空間距離；兩星相互相位之間的空間；一星接近另一星之際；任一星與所問事件相關宮位之間的空間；一星下降時的增減變化；徵象星位置的變動；以及行星接近其本位之際。"},
    {"id": 82, "text": "當圖形可能平衡時，應觀察新月或滿月時的星盤，若此時圖形亦平衡，則勿急於下判斷。"},
    {"id": 83, "text": "獲得恩賜之時，顯示申請者與其君主之間的情感關係；但「座位」則揭示該職位之性質。"},
    {"id": 84, "text": "若火星為上升點之主星，且位於第二宮，或與第二宮之主星相合，則將帶來許多災禍。"},
    {"id": 85, "text": "若上升點之主星與第二宮之主星形成相位，君王將自發地製造諸多指控。"},
    {"id": 86, "text": "太陽乃生命之力的源頭；月亮則為自然之力的源頭。"},
    {"id": 87, "text": "月球運行週期約為二十八日二小時十八分鐘。部分占星師亦依據太陽的進度來作判斷，即以其起始時所佔之度數與分數為準。"},
    {"id": 88, "text": "在推算命運宮一整年運勢時，應從上升點起算，量取等同於太陽與月亮之間的距離。"},
    {"id": 89, "text": "祖父之事宜從第七宮推斷，叔伯之事則從第六宮推斷。"},
    {"id": 90, "text": "若命主星與上升點成相位，隱藏之事或物質將與上升點性質相符；但若上升點未與命主星成相位，則事件之本質將依命主星所在宮位而定。時辰之主星顯示其色彩；月亮所在宮位顯示其時間；若在地平線之上，代表新事；若在地平線之下，則代表舊事。命運宮顯示其數量，無論長短。各宮主星、下天與中天之主星，以及月亮，皆顯示其本質或價值。"},
    {"id": 91, "text": "若病者之命主星呈燃燒狀態，乃不祥之兆；尤其當命運宮受影響時更甚。"},
    {"id": 92, "text": "土星若位於東方，對病人之危害較輕；火星若位於西方，亦非極度有害。"},
    {"id": 93, "text": "判斷不可僅憑單一星象，須待下一相位出現後再綜合考量：因每一個相位皆會改變原則；故為避免錯誤，應同時結合最後一個與下一個相位。"},
    {"id": 94, "text": "勢力較強之命主星所在宮位，可顯示求問者之思緒。"},
    {"id": 95, "text": "與第十宮一同升起之星辰，可證明命主適合其所從事之職業程度。"},
    {"id": 96, "text": "日月食期間，最接近四角點之星辰所呈現之徵兆，即為所預示之事。星辰之本質需配合日月食現象，包括行星與恆星，以及其外觀表現。"},
    {"id": 97, "text": "若新月或滿月之主星位於角度之上，所詢之事將迅速實現。"},
    {"id": 98, "text": "流星與如飛髮般墜落的隕石，在占卜中僅佔次要地位。"},
    {"id": 99, "text": "流星象徵空氣乾燥；若其僅朝單一方向射出，則預示該處有風；若朝多個方向散射，則預示水位下降、大氣紊亂及軍隊入侵。"},
    {"id": 100, "text": "若彗星距太陽十一宮之遠，且出現於角度上，則某國之君王或王室重臣將亡。若其位於繼承宮，則國庫將興旺，但統治者或地方官將更替。若其位於衰敗宮，則將爆發疾病與猝死。若彗星自西向東移動，外敵將入侵；若未移動，則敵人將為地方勢力或國內叛亂者。"}
]

# ==================== 實用函式 ====================
def get_random_aphorism() -> Dict:
    """隨機返回一條格言（適合首頁或每日一論）"""
    return random.choice(CENTILOQUY)

def search_aphorism(keyword: str) -> List[Dict]:
    """按關鍵字搜尋格言"""
    keyword = keyword.lower()
    return [item for item in CENTILOQUY if keyword in item["text"].lower()]

def get_aphorism_by_id(aphorism_id: int) -> Optional[Dict]:
    """依編號取得單一格言"""
    for item in CENTILOQUY:
        if item["id"] == aphorism_id:
            return item
    return None

def get_all_aphorisms() -> List[Dict]:
    """返回全部 100 條（用於列表顯示）"""
    return CENTILOQUY

# ==================== Streamlit 顯示輔助 ====================
def format_aphorism(aphorism: Dict) -> str:
    """格式化單一格言為易讀文字"""
    return f"**第 {aphorism['id']} 條**\n\n{aphorism['text']}"

# ==================== 測試 ====================
if __name__ == "__main__":
    print(format_aphorism(get_random_aphorism()))
